 27	interface QuickSearchListProps {
 28	  listItems: CatalogItem[];
 29	  catalogItemTypes: CatalogType[];
 30	  viewAll?: CatalogLinkData[];
 31	  selectedItemId: string;
 32	  searchTerm: string;
 33	  namespace: string;
 34	  limitItemCount?: number;
 35	  onSelectListItem: (
 36	    event: React.MouseEvent<Element, MouseEvent> | React.KeyboardEvent<Element>,
