 44	  listItems,
 45	  catalogItemTypes,
 46	  viewAll,
 47	  selectedItemId,
 48	  onSelectListItem,
 49	  closeModal,
 50	  limitItemCount,
 51	  onListChange,
 52	}) => {
 53	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 54	  const history = useHistory();
 55	  const [itemsCount, setItemsCount] = React.useState<number>(
 56	    limitItemCount || listItems.length,
 57	  );
 58	  const listHeight =
 59	    document.querySelector('.ocs-quick-search-list__list')?.clientHeight || 0;
 60	
