149	                            </SplitItem>
150	                            {item?.secondaryLabel && (
151	                              <SplitItem className="ocs-quick-search-list__secondary-label">
152	                                {item.secondaryLabel}
153	                              </SplitItem>
154	                            )}
155	                          </Split>
156	                        </SplitItem>
157	                        <SplitItem>
158	                          <TextContent
159	                            data-test={`item-name-${item.name}-${item.provider}-secondary-label`}
160	                          >
161	                            <Text component={TextVariants.small}>
162	                              {item.provider}
163	                            </Text>
164	                          </TextContent>
165	                        </SplitItem>
166	                      </Split>
167	                    </DataListCell>,
168	                  ]}
169	                />
170	              </DataListItemRow>
171	            </DataListItem>
172	          );
173	        })}
174	      </DataList>
175	
176	      {viewAll?.length > 0 && (
